**Implementation in `ui/ribbon.rs`, `ui/toolbar.rs`, `tabs/state.rs`, and `app_state.rs`:**

1. **File Type Detection in Tab struct:**
Extend `Tab` with file type enum and detection:
```rust
#[derive(Clone, Copy, PartialEq)]
pub enum FileType {
    Markdown,
    Json,
    Yaml,
    Toml,
    Unknown,
}

impl Tab {
    pub fn file_type(&self) -> FileType {
        let ext = self.path.extension().and_then(|s| s.to_str());
        match ext {
            Some("json") => FileType::Json,
            Some("yaml") | Some("yml") => FileType::Yaml,
            Some("toml") => FileType::Toml,
            Some("md") => FileType::Markdown,
            _ => FileType::Unknown,
        }
    }
}
```

2. **Dynamic Toolbar in `ui/ribbon.rs`:**
Create `AdaptiveToolbar` widget that consumes active tab's file type:
```rust
fn adaptive_toolbar(ui: &mut egui::Ui, active_tab: &Tab, app_state: &mut AppState) {
    let ft = active_tab.file_type();

    // Markdown-specific buttons (hide for structured data)
    if ft == FileType::Markdown {
        if ui.button("🅱 Bold").clicked() { /* toggle bold */ }
        if ui.button("🅸 Italic").clicked() { /* toggle italic */ }
        if ui.button("H1").clicked() { /* insert heading */ }
    }

    // Structured data buttons
    match ft {
        FileType::Json | FileType::Yaml | FileType::Toml => {
            if ui.button("Format").clicked() { format_structured(active_tab); }
            if ui.button("Validate").clicked() { validate_structured(active_tab); }
            if ui.button("Tree View").clicked() { toggle_tree_view(app_state); }
        }
        _ => {},
    }

    // Always available: Save, Undo, Find
    if ui.button("💾").clicked() { save_file(active_tab); }
}
```

